use dep::poseidon::poseidon2;

// === Byte conversion explained ===
// All to_be_bytes functions break a number into individual bytes (big-endian = left-to-right).
// Example: 0x1A2B3C4D -> [0x1A, 0x2B, 0x3C, 0x4D]
//
// `& 0xff` takes the rightmost hex pair (one byte): 0x1A2B3C4D -> 0x4D
// `>> 8` chops that pair off: 0x1A2B3C4D -> 0x001A2B3C
// Fills from the end (`bytes[N-i]`) so the final array reads left-to-right.
//
// === Nullifier explained ===
// Hashes a 64-byte ECDSA signature into a single Field using Poseidon2.
// ECDSA signatures are deterministic (RFC 6979): same wallet + same message = same signature.
// So hash(signature) = unique fingerprint per (wallet, claim). Prevents double-proving.
//
// Poseidon2 operates on Field elements, not bytes. One Field can't hold 64 bytes (overflow),
// so we pack 8 bytes per Field using base-256 accumulation:
//   `chunk * 256 + byte` -- bytes [0x11, 0x22] -> 0 * 256 + 0x11 = 0x11 -> 0x11 * 256 + 0x22 = 0x1122
// Poseidon2 is used over SHA/Keccak because it's ~100x cheaper inside ZK circuits.

// Helper function to convert u128 to big-endian bytes
pub fn u128_to_be_bytes(value: u128) -> [u8; 16] {
    let mut bytes: [u8; 16] = [0; 16];
    let mut remaining = value;

    for i in 0..16 {
        bytes[15 - i] = (remaining & 0xff) as u8;
        remaining = remaining >> 8;
    }

    bytes
}

// Helper function to convert u64 to big-endian bytes
pub fn u64_to_be_bytes(value: u64) -> [u8; 8] {
    let mut bytes: [u8; 8] = [0; 8];
    let mut remaining = value;

    for i in 0..8 {
        bytes[7 - i] = (remaining & 0xff) as u8;
        remaining = remaining >> 8;
    }

    bytes
}

// Computes a deterministic nullifier from the signature
// Since signatures are deterministic (RFC 6979), same signer + message = same nullifier
pub fn compute_nullifier(signature: [u8; 64]) -> Field {
    // Convert signature bytes to Fields for Poseidon hashing
    // Split signature into 8-byte chunks to avoid overflow
    let mut sig_fields: [Field; 8] = [0; 8];

    for i in 0..8 {
        let mut chunk: Field = 0;
        for j in 0..8 {
            chunk = chunk * 256 + (signature[i * 8 + j] as Field);
        }
        sig_fields[i] = chunk as Field;
    }

    // Hash using Poseidon2
    poseidon2::Poseidon2::hash(sig_fields, 8)
}

// Helper function to convert u32 to big-endian bytes
pub fn u32_to_be_bytes(value: u32) -> [u8; 4] {
    let mut bytes: [u8; 4] = [0; 4];
    let mut remaining = value;

    for i in 0..4 {
        bytes[3 - i] = (remaining & 0xff) as u8;
        remaining = remaining >> 8;
    }

    bytes
}

